import{_ as a,o as s,c as t,a6 as i,eo as o,ep as l,eq as n,er as e,es as g,et as p,eu as h,ev as d,ew as c,ex as m,ey as _,ez as u,eA as b,eB as f,eC as k}from"./chunks/framework.UYVGz2W_.js";const C=JSON.parse('{"title":"アーティストとしてのはじめ方","description":"","frontmatter":{},"headers":[],"relativePath":"ja/artist/index.md","filePath":"ja/artist/index.md"}'),P={name:"ja/artist/index.md"};function x(T,r,v,y,S,w){return s(),t("div",null,[...r[0]||(r[0]=[i('<h1 id="アーティストとしてのはじめ方" tabindex="-1">アーティストとしてのはじめ方 <a class="header-anchor" href="#アーティストとしてのはじめ方" aria-label="Permalink to “アーティストとしてのはじめ方”">​</a></h1><p>このガイドでは、Kitsuの主要な機能を理解し、アーティストとしての利用を開始するための手順を説明します。</p><hr><h2 id="初期設定とプロフィールのカスタマイズ" tabindex="-1">初期設定とプロフィールのカスタマイズ <a class="header-anchor" href="#初期設定とプロフィールのカスタマイズ" aria-label="Permalink to “初期設定とプロフィールのカスタマイズ”">​</a></h2><p>最初にプロフィールを設定し、個人情報を更新してKitsuのインターフェイスをカスタマイズします。これにより、チームメンバーがあなたを認識しやすくなり、通知や設定をワークフローに合わせて調整できます。</p><ol><li><p><strong>プロフィールにアクセス</strong>:<br> 画面右上のアバターをクリックし、<strong>プロフィール</strong>を選択します。</p></li><li><p><strong>体験をカスタマイズ</strong>:</p><ul><li>名前、メールアドレス、電話番号、タイムゾーン、言語を更新します。</li><li>他のメンバーが認識しやすいようにアバター写真をアップロードします。</li><li>通知の受信方法（メールまたはSlack）を選択します。</li><li><strong>テーマ</strong>カラーを選択し、<strong>サポートチャット</strong>の表示/非表示を切り替えます。</li></ul></li></ol><p><img src="'+o+'" alt="User profile"></p><div class="tip custom-block"><p class="custom-block-title">プロのヒント</p><p>このセクションでは、<strong>ドキュメント</strong>、<strong>チュートリアル</strong>、私たちの<strong>Discordコミュニティ</strong>、<strong>YouTubeチャンネル</strong>、および公開<strong>ロードマップ</strong>へのクイックリンクも提供されています。いつでも役立つリソースにアクセスできます。</p></div><p>セキュリティを強化するため、デフォルトのパスワードを強力で一意のパスワードに変更することをお勧めします。</p><p><img src="'+l+'" alt="Change password"></p><hr><h2 id="担当タスクの管理" tabindex="-1">担当タスクの管理 <a class="header-anchor" href="#担当タスクの管理" aria-label="Permalink to “担当タスクの管理”">​</a></h2><p><strong>My Tasks</strong>ページは、割り当てられたタスクを管理する主要なハブで、ログインすると自動的に表示されます。ここでは、割り当てられたタスクのリストと主要な情報を確認できます。</p><h3 id="利用可能な主要情報" tabindex="-1">利用可能な主要情報: <a class="header-anchor" href="#利用可能な主要情報" aria-label="Permalink to “利用可能な主要情報:”">​</a></h3><ul><li><strong>Production</strong>: タスクが関連付けられているプロジェクト。</li><li><strong>Entity</strong>: 割り当てられた特定のアセットやショット。</li><li><strong>Estimates &amp; Duration</strong>: タスクの時間に関する情報。</li><li><strong>Due Date</strong>: タスクの締切。</li><li><strong>Status</strong>と<strong>Priority</strong>: タスクの緊急度を理解するための重要な詳細。</li></ul><p><img src="'+n+'" alt="My tasks page"></p><h3 id="追加機能" tabindex="-1">追加機能: <a class="header-anchor" href="#追加機能" aria-label="Permalink to “追加機能:”">​</a></h3><ul><li><strong>Show</strong>ドロップダウンでは、<strong>すべてのタスク</strong>または<strong>今週の期限</strong>にフォーカスするタスクを選択できます。</li><li><strong>Sorted By</strong>ドロップダウンでは、タスクを<strong>名前</strong>、<strong>優先度</strong>、<strong>ステータス</strong>、<strong>見積もり</strong>、または<strong>最終コメント</strong>で並べ替えることができます。</li><li>これらのフィルターを使用してタスクリストを絞り込むか、検索ボックスで特定のタスクを見つけてください。</li></ul><p><img src="'+e+'" alt="Task sorting and filtering"></p><p><strong>My Tasks</strong>ページには以下の方法でアクセスできます:</p><ul><li>画面上部のショートカット。</li><li>メインメニューの<strong>User</strong>セクション内の<strong>MY TASKS</strong>。</li><li>Kitsuロゴをクリック。 <img src="'+g+'" alt="Main menu"></li></ul><hr><h2 id="タスク進捗の更新" tabindex="-1">タスク進捗の更新 <a class="header-anchor" href="#タスク進捗の更新" aria-label="Permalink to “タスク進捗の更新”">​</a></h2><p>タスクの進捗状況が進んだら、その状態をチームに知らせる必要があります。</p><h3 id="タスクのステータスを更新する" tabindex="-1">タスクのステータスを更新する <a class="header-anchor" href="#タスクのステータスを更新する" aria-label="Permalink to “タスクのステータスを更新する”">​</a></h3><ol><li><strong>My Tasks</strong>ページまたは関連アセットページでタスクの<strong>ステータス</strong>アイコンをクリックします。</li><li>コメントを追加して進捗状況を報告したり、質問をしたりします。</li><li>ステータスを変更します（例:「Ready」から「WIP」）。</li><li><strong>Post</strong>をクリックして変更を保存します。</li></ol><p><img src="'+p+'" alt="Changing status"></p><p>最新のコメントを編集するには、<strong>History</strong>ボタンをクリックし、<strong>Edit</strong>を選択します。 <img src="'+h+'" alt="Edit button"></p><hr><h2 id="タスクの確認-ボードビュー" tabindex="-1">タスクの確認 (ボードビュー) <a class="header-anchor" href="#タスクの確認-ボードビュー" aria-label="Permalink to “タスクの確認 (ボードビュー)”">​</a></h2><p><strong>Board Tab</strong>では、ステータスに基づいて列に整理されたタスクを表示できます。各タスクカードには以下が含まれます:</p><ul><li>サムネイル</li><li>タスクタイプ名</li><li>エンティティ名</li></ul><p><img src="'+d+'" alt="Board view"></p><ul><li>カードをクリックすると、右側にパネルが開き、コメントを表示または追加できます。</li><li>タスクのステータスを更新するには、目的の列にドラッグします。</li></ul><hr><h2 id="タスクの確認-カレンダービュー" tabindex="-1">タスクの確認 (カレンダービュー) <a class="header-anchor" href="#タスクの確認-カレンダービュー" aria-label="Permalink to “タスクの確認 (カレンダービュー)”">​</a></h2><p><strong>Calendar View</strong>では、タスクが<strong>開始日</strong>と<strong>期限</strong>に基づいてカレンダーに表示されます。複数日にわたるタスクはカレンダー上で視覚的に拡張されます。</p><p><img src="'+c+'" alt="Calendar view"></p><ul><li>タスクをクリックすると、右側にパネルが開き、更新やコメントが可能です。</li><li>他のビューと同様に、ここでもタスクを並べ替えたり、フィルターをかけたりできます。</li></ul><hr><h2 id="コンセプトの共有" tabindex="-1">コンセプトの共有 <a class="header-anchor" href="#コンセプトの共有" aria-label="Permalink to “コンセプトの共有”">​</a></h2><p><strong>コンセプトアーティスト</strong>の場合、コンセプトをアップロードして共有できます。</p><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード: <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード:”">​</a></h3><ol><li><strong>Todo Page</strong>から<strong>Return to Production</strong>をクリックしてダッシュボードにアクセスします。</li><li>メインメニューから<strong>Concepts</strong>ページに移動します。</li><li><strong>Add a new reference to concepts</strong>をクリックし、ファイルをアップロードします。</li></ol><p><img src="'+m+'" alt="Upload concepts"></p><h3 id="コンセプトをアセットにリンクする" tabindex="-1">コンセプトをアセットにリンクする: <a class="header-anchor" href="#コンセプトをアセットにリンクする" aria-label="Permalink to “コンセプトをアセットにリンクする:”">​</a></h3><p>コンセプトをアップロードしたら、それをアセットにリンクして、適切な制作要素と関連付けます。これにより、チームが正しいコンテキストで参照し、フィードバックを提供しやすくなります。</p><ol><li>コンセプトのコメントパネルを開き、<strong>Link</strong>をクリックします。</li><li>コンセプトに関連付けるアセットを選択します。</li></ol><p><img src="'+_+'" alt="Link assets"></p><hr><h2 id="レビューのリクエスト" tabindex="-1">レビューのリクエスト <a class="header-anchor" href="#レビューのリクエスト" aria-label="Permalink to “レビューのリクエスト”">​</a></h2><p>タスクが完了したら、レビューをリクエストできます。その手順は以下の通りです:</p><ol><li>タスクステータスを<strong>Waiting for Approval (WFA)</strong>に変更します。</li><li>プレビューファイルをドラッグしてアップロードエリアにドロップするか、<strong>Attach Preview</strong>をクリックして添付します。</li><li><strong>Post</strong>をクリックして送信を完了します。</li></ol><p><img src="'+u+'" alt="Request review"></p><p>以前のリビジョンは保存され、参照用にアクセス可能なままです。</p><p><img src="'+b+'" alt="Revision history"></p><hr><h2 id="タイムシートの記入" tabindex="-1">タイムシートの記入 <a class="header-anchor" href="#タイムシートの記入" aria-label="Permalink to “タイムシートの記入”">​</a></h2><p>制作で必要な場合は、<strong>Timesheets</strong>タブまたは画面上部の<strong>Timesheets</strong>ショートカットボタンを使用して作業時間を記録します。</p><h3 id="時間を記録する方法" tabindex="-1">時間を記録する方法: <a class="header-anchor" href="#時間を記録する方法" aria-label="Permalink to “時間を記録する方法:”">​</a></h3><ul><li>各タスクの横にあるスライダーを使用して作業時間を記録します。</li><li>簡単に入力するには、<strong>1時間</strong>、<strong>4時間</strong>、<strong>8時間</strong>のボタンを使用します。</li></ul><p><img src="'+f+'" alt="Timesheet view"></p><h3 id="記録漏れの日は" tabindex="-1">記録漏れの日は？ <a class="header-anchor" href="#記録漏れの日は" aria-label="Permalink to “記録漏れの日は？”">​</a></h3><p>日付選択ツールをクリックしてエントリを埋め戻します。作業していない日は<strong>Day Off</strong>としてマークすることもできます。</p><p><img src="'+k+'" alt="Backfill timesheets"></p>',65)])])}const B=a(P,[["render",x]]);export{C as __pageData,B as default};
